#!/usr/bin/env node

/**
 * One-time setup script: Generate an initial page-map.json by discovering
 * ERP page directories and docs content sections, then matching them.
 *
 * Per D-08: page-map.json is initially generated by this script,
 * then manually maintained as the ERP evolves.
 *
 * Usage:
 *   node generate-page-map.mjs <erpRepoPath> <docsRepoPath>
 *   node generate-page-map.mjs --audit <erpRepoPath>
 *   node generate-page-map.mjs --help
 */

import { readdir, readFile } from 'node:fs/promises';
import { join, basename } from 'node:path';

const HELP_TEXT = `
generate-page-map.mjs - Generate or audit page-map.json for ERP-to-docs mapping

Usage:
  node generate-page-map.mjs <erpRepoPath> <docsRepoPath>
    Discover ERP page directories and docs sections, propose a page-map.json.

  node generate-page-map.mjs --audit <erpRepoPath>
    Compare ERP directories against existing page-map.json and report unmapped dirs.

  node generate-page-map.mjs --help
    Show this help message.

Arguments:
  erpRepoPath   Path to the despensinha-admin-app repository
  docsRepoPath  Path to easypdv-admin-docs or easypdv-admin-docs-dev repository

Examples:
  node generate-page-map.mjs /path/to/despensinha-admin-app /path/to/easypdv-admin-docs
  node generate-page-map.mjs --audit /path/to/despensinha-admin-app
`.trim();

/**
 * Normalize a directory name for fuzzy matching.
 * Removes hyphens, underscores, and converts to lowercase.
 * @param {string} name
 * @returns {string}
 */
function normalize(name) {
  return name.toLowerCase().replace(/[-_]/g, '');
}

/**
 * List subdirectories of a given path.
 * @param {string} dirPath
 * @returns {Promise<string[]>}
 */
async function listSubdirs(dirPath) {
  try {
    const entries = await readdir(dirPath, { withFileTypes: true });
    return entries.filter((e) => e.isDirectory()).map((e) => e.name);
  } catch {
    return [];
  }
}

/**
 * Generate a proposed page-map.json from ERP and docs directories.
 * @param {string} erpRepoPath
 * @param {string} docsRepoPath
 */
async function generatePageMap(erpRepoPath, docsRepoPath) {
  const erpPagesDir = join(erpRepoPath, 'src', 'app', 'pages');
  const docsLatestDir = join(docsRepoPath, 'src', 'content', 'docs', 'latest');

  const erpDirs = await listSubdirs(erpPagesDir);
  const docsDirs = await listSubdirs(docsLatestDir);

  if (erpDirs.length === 0) {
    console.error(`No directories found in ${erpPagesDir}`);
    console.error('Verify the ERP repository path is correct.');
    process.exit(1);
  }

  // Detect repo type from path
  const repoType = docsRepoPath.includes('-dev') ? 'dev' : 'user';

  // Build normalized docs lookup
  const docsNormalized = new Map();
  for (const dir of docsDirs) {
    docsNormalized.set(normalize(dir), dir);
  }

  const mappings = [];
  const unmappedErp = [];

  for (const erpDir of erpDirs) {
    const erpPath = `src/app/pages/${erpDir}/`;
    const normalizedErp = normalize(erpDir);

    // Try exact normalized match
    const matchedDoc = docsNormalized.get(normalizedErp);

    if (matchedDoc) {
      mappings.push({
        erpDir: erpPath,
        docSection: `latest/${matchedDoc}/`,
        description: `${erpDir} module`,
      });
    } else {
      // No match found
      mappings.push({
        erpDir: erpPath,
        docSection: null,
        description: `${erpDir} - no matching docs section found`,
      });
      unmappedErp.push(erpDir);
    }
  }

  // Add standard non-page directories
  const standardDirs = [
    { erpDir: 'src/app/modules/', docSection: null, description: 'Shared modules - no direct doc mapping' },
    { erpDir: 'src/shared/', docSection: null, description: 'Shared utilities - no direct doc mapping' },
    { erpDir: 'src/api/', docSection: null, description: 'API layer - no direct doc mapping' },
    { erpDir: 'src/_metronic/', docSection: null, description: 'Metronic template - always skip' },
  ];

  const pageMap = {
    repoType,
    mappings: [...mappings, ...standardDirs],
  };

  console.log(JSON.stringify(pageMap, null, 2));

  if (unmappedErp.length > 0) {
    console.error('\n--- Unmapped ERP directories (no matching docs section) ---');
    for (const dir of unmappedErp) {
      console.error(`  - ${dir}`);
    }
    console.error('\nThese may need new docs pages or explicit null mappings.');
  }

  console.error('\nReview the output and save to scripts/ai/page-map.json');
  console.error(`Detected ${erpDirs.length} ERP page dirs, ${docsDirs.length} docs sections, ${mappings.length - unmappedErp.length} matched.`);
}

/**
 * Audit an existing page-map.json against current ERP directories.
 * @param {string} erpRepoPath
 */
async function auditPageMap(erpRepoPath) {
  const erpPagesDir = join(erpRepoPath, 'src', 'app', 'pages');
  const erpDirs = await listSubdirs(erpPagesDir);

  if (erpDirs.length === 0) {
    console.error(`No directories found in ${erpPagesDir}`);
    process.exit(1);
  }

  // Load existing page-map.json
  const pageMapPath = new URL('./page-map.json', import.meta.url).pathname;
  let pageMap;
  try {
    const raw = await readFile(pageMapPath, 'utf-8');
    pageMap = JSON.parse(raw);
  } catch {
    console.error(`Could not load page-map.json at ${pageMapPath}`);
    console.error('Run generate mode first to create the initial mapping.');
    process.exit(1);
  }

  const mappedErpDirs = new Set(
    pageMap.mappings.map((m) => m.erpDir.replace(/^src\/app\/pages\//, '').replace(/\/$/, ''))
  );

  const newDirs = erpDirs.filter((dir) => !mappedErpDirs.has(dir));

  if (newDirs.length === 0) {
    console.log('All ERP page directories are mapped in page-map.json.');
    console.log(`Total: ${erpDirs.length} directories, all accounted for.`);
  } else {
    console.log(`Found ${newDirs.length} new unmapped ERP directories:\n`);
    for (const dir of newDirs) {
      console.log(`  - src/app/pages/${dir}/`);
    }
    console.log('\nAdd these to page-map.json with appropriate docSection values.');
  }
}

// --- CLI entry point ---
const args = process.argv.slice(2);

if (args.includes('--help') || args.includes('-h')) {
  console.log(HELP_TEXT);
  process.exit(0);
}

if (args[0] === '--audit') {
  const erpPath = args[1];
  if (!erpPath) {
    console.error('Usage: node generate-page-map.mjs --audit <erpRepoPath>');
    process.exit(1);
  }
  await auditPageMap(erpPath);
} else if (args.length >= 2) {
  const [erpPath, docsPath] = args;
  await generatePageMap(erpPath, docsPath);
} else {
  console.error('Invalid arguments. Use --help for usage information.');
  process.exit(1);
}
